import React, { useEffect, useState } from 'react';
import api from '../api';
import moment from 'moment';

const OrderHistoryPage = () => {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

const user = JSON.parse(localStorage.getItem("user"));

  console.log(user);
  
  useEffect(() => {
    localStorage.getItem("user", JSON.stringify(user))
    const fetchOrders = async () => {
      try {
        const res = await api.post(`/orders/history/${user.id}`);
        setOrders(res.data);
      } catch (err) {
        console.error('Failed to fetch order history:', err);
        setError('Failed to load order history');
      }
      setLoading(false);
    };

    fetchOrders();
  }, []);

  return (
    <div className="container mt-5">
      <h2 className="mb-4">📜 Your Order History</h2>

      {loading && <div>Loading...</div>}
      {error && <div className="alert alert-danger">{error}</div>}

      {!loading && !error && orders.length === 0 && (
        <div className="alert alert-info">You haven’t placed any orders yet.</div>
      )}

      {!loading && orders.length > 0 && (
        <div className="col-md-8">
          <div className="card shadow-sm border-0 h-100">
            <div className="card-body">
              <h4 className="card-title mb-4">📦 Your Orders</h4>
              
              <p>Total Orders: <strong>{orders.length}</strong></p>

              {orders.length === 0 ? (
                <p className="text-muted">You have no orders yet.</p>
              ) : (
                <div className="list-group">
                  {orders.map((order, index) => (
                    <div key={index} className="list-group-item mb-3">
                      <div className="d-flex justify-content-between">
                        <div>
                          <h6>Order ID: <code>{order.token}</code></h6>
                          <p className="mb-1">Status: <strong>{order.status}</strong></p>
                          <p className="mb-1">Payment: <strong>{order.payment}</strong></p>
                          <p className="mb-1">Total Price: ₹{order.totalPrice}</p>
                        </div>
                        <div>
                          <h6>Items:</h6>
                          <ul className="list-unstyled">
                            {order.items.map((item, idx) => (
                              <li key={idx}>
                                🍔 {item.food.name} × {item.quantity}
                              </li>
                            ))}
                          </ul>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default OrderHistoryPage;
